widget.tizen:content-security-policy:
default-src 'self' data: blob: https://streaming.lavozsalsa.com;
script-src 'self' 'unsafe-inline' 'unsafe-eval' $WEBAPIS;
style-src 'self' 'unsafe-inline';
img-src 'self' data: blob:;
media-src https://streaming.lavozsalsa.com blob:;
connect-src https://streaming.lavozsalsa.com https://*.lavozsalsa.com;
